<template>
  <div class="max-w-4xl mx-auto py-12 px-4">
    <Card class="mb-8 shadow-xl">
      <h2 class="text-2xl font-bold mb-1">Welcome, {{ userFullName }}!</h2>
      <p class="text-gray-500 mb-2">This is your Repair Portal dashboard.</p>
      <div class="flex flex-row gap-2">
        <Button @click="goToNewTicket" variant="solid" icon-left="plus">Create New Repair Ticket</Button>
        <Button @click="refreshTickets" :loading="tickets.loading" icon-left="refresh-cw">Refresh</Button>
        <Button @click="session.logout.submit()" variant="outline" icon-left="log-out">Logout</Button>
      </div>
    </Card>

    <Card class="mb-8">
      <h3 class="text-lg font-bold mb-3">Your Recent Repair Tickets</h3>
      <div v-if="tickets.data && tickets.data.length">
        <ul>
          <li v-for="ticket in tickets.data" :key="ticket.name" class="mb-2">
            <div class="flex flex-row justify-between items-center">
              <span>
                <b>#{{ ticket.name }}</b> — {{ ticket.status }} <span v-if="ticket.instrument">({{ ticket.instrument }})</span>
              </span>
              <Button size="sm" variant="secondary" @click="goToTicket(ticket.name)">View</Button>
            </div>
          </li>
        </ul>
      </div>
      <div v-else class="text-gray-400">No tickets found. Try creating one!</div>
    </Card>

    <Dialog v-model="showDialog" title="Need Help?">
      <p>Contact support or view documentation for assistance.</p>
    </Dialog>
    <Button variant="ghost" icon-left="help-circle" @click="showDialog = true">Help</Button>
  </div>
</template>

<script setup>
import { Card, Button, Dialog, createResource } from "frappe-ui"
import { session } from "../data/session"
import { ref, computed } from "vue"
import { useRouter } from "vue-router"

// Fetch user full name (if available in your user resource)
const userFullName = computed(() => session.user?.full_name || session.user || "User")

const router = useRouter()
const showDialog = ref(false)

function goToNewTicket() {
  router.push({ name: "RepairTicketNew" }) // adjust route name if needed
}

function goToTicket(name) {
  router.push({ name: "RepairTicketView", params: { name } }) // adjust route name if needed
}

// Fetch recent tickets for the logged-in user
const tickets = createResource({
  url: "repair_portal.api.get_my_tickets", // assumes you have this API method!
  auto: true,
  params: () => ({
    limit: 5,
    user: session.user,
  }),
})

function refreshTickets() {
  tickets.reload()
}
</script>
